using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    const long long INF = 1e18;
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, INF)));
    dist[0][0][1] = 1;

    priority_queue<pair<long long, pair<int, pair<int, int>>>, vector<pair<long long, pair<int, pair<int, int>>>>, greater<>> pq;
    pq.push({-dist[0][0][1], {0, {0, 1}}});

    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};

    while (!pq.empty()) {
        auto [current_cost_neg, current] = pq.top();
        pq.pop();

        long long current_cost = -current_cost_neg;

        int i = current.first;
        int j = current.second.first;
        int parity = current.second.second;

        if (i == m-1 && j == n-1) {
            return current_cost;
        }

        if (parity == 1) {
            for (auto [di, dj] : directions) {
                int ni = i + di;
                int nj = j + dj;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long long new_cost = current_cost + (ni + 1) * (nj + 1);
                    if (new_cost < dist[ni][nj][0]) {
                        dist[ni][nj][0] = new_cost;
                        pq.push({-new_cost, {ni, {nj, 0}}});
                    }
                }
            }
        } else {
            long long new_cost = current_cost + waitCost[i][j];
            if (new_cost < dist[i][j][1]) {
                dist[i][j][1] = new_cost;
                pq.push({-new_cost, {i, {j, 1}}});
            }
        }
    }

    return -1;
}
